#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100
struct Student {
    char name[MAX];
    int time;
};
int compare(const void *a, const void *b) {
    struct Student *s1 = (struct Student *)a;
    struct Student *s2 = (struct Student *)b;
    return s1->time - s2->time;
}
int main() {
    int n;
    scanf("%d", &n);
    struct Student students[n];
    for (int i = 0; i < n; i++) {
        scanf("%s %d", students[i].name, &students[i].time);
    }
    qsort(students, n, sizeof(struct Student), compare);
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (students[i].time <= 0) {
            count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

