code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let students = [];
let count = 0;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        let [name, time] = input.split(' ');
        time = parseInt(time);
        students.push({ name, time });
        if (students.length === n) {
            students.sort((a, b) => a.time - b.time);
            for (let student of students) {
                if (student.time <= 0) {
                    count++;
                }
            }
            console.log(count);
            rl.close();
        }
    }
});
